INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('customs-f19eb2bd-moex-00047', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「臺灣森林分為天然林與人工林，目前天然林因保育而全面禁伐，但人工 林則否。在世界提倡淨碳排的趨勢下，森林『碳匯』議題越來越被重視—— 意即森林具有固碳功能，可以將二氧化碳吸存固著於自然環境中，形成如 同把錢存在銀行一樣的倉庫。因此，要增加碳匯，就必須多造林。然而， 樹木會老化，過了 20 年的生長巔峰期，固碳能力逐年下降，最後失去固 碳功能，是以人工林的更新有其必要性。」 根據上文，下列選項最符合文意的是：', '["樹齡越大、枝葉越茂盛，對環境保護的效益越大", "人工林的造林和定期採伐，有其實質上的必要性", "環境意識的崛起，禁伐已是全球山林保育的趨勢", "天然林比人工林更具有碳匯的效益，可增加獲利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00048', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '某企業代表在產業高峰會中表示：「為了能招募外國人才，加上臺灣環境 資源有限，包括土地、水、電，走出臺灣是不得不做的事情。然而在海外 布局的過程面臨兩個挑戰，首先是全球人才不足，不僅人口變少，念半導 體的人也變少。另一個挑戰是文化融合，應以開放心態因應。全球化布局 可能造成成本增加，增加的成本是由客戶吸收，或企業自行吸收，將會是 挑戰，也是企業全球化要面對的議題。」 根據上文，下列選項何者正確？', '["產業發展必須倚賴全球人才，但也要考慮文化融合的衝擊", "受新冠肺炎疫情影響，人才流動受限，因此必須走出臺灣", "為了產品標準化，應該統一各地製程、管理、營運之步驟", "全球布局能利用各地廉價的勞工、土地、水電，降低成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00049', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「一葉知秋，一根頭髮可以讓罪犯無所遁形。可見，頭髮就是人這棵樹的 葉子。秋天到了，葉轉黃，年紀大了，髮變白。人與時間拔河，以白髮為 繩。老，本是自然律裡的事，擋不了也無須擋。一派天真自然，反而能使 『老』這件事顯出美好的部分。我不討厭白髮，有時還覺得有些人的白髮 長得真好看。如果一棵樹的葉子綠得像幫派，看久了會膩，若泛起霜紅色 澤，美就來了。人亦如此，渾身上下要一起老才好。白髮是落雪天氣，人 生走到這一步，離暴動份子的時代遠了，較接近沉思的智者。」 根據上文，下列選項何者最符合文意？', '["活到老，學到老", "老吾老，以及人之老", "夕陽無限好，正是近黃昏", "人間只道黃金貴，不問天公買少年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00050', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「人天生就有建築的本能。《高塔，一種□□□□的建築》一書中，描述 一個事業受挫、婚姻失敗的中年人，自己到野外湖濱建造高塔的過程。雖 然不是建築科班出身，但他受到內心本能的驅使，開始在湖邊建造一座高 塔。過程中，他感受到內心的沉澱與改變。等到高塔建造完成，他似乎得 到了某種力量，又可以重新去面對自己不完美的人生。」 根據文意，最適合填入□□□□，用以描述文中高塔特質的選項是：', '["隨心所欲", "自我療癒", "挑戰極限", "睥睨天下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00051', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '一般航海所用之方向有4種，其中電羅經方向乃以下列何者為基準量度之方向？', '["地球子午線", "磁子午線", "羅盤磁針之軸", "旋轉儀之軸"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d30ec6e36a01", "answer_pdf_sha1": "4ceedca82e31", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00052', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '長程無線電警告系統共分為幾個航區？美國則是第幾航區的協調官？', '["21區；第7、15區", "24區；第9、22區", "21區；第4、12區", "24區；第13、18區"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d30ec6e36a01", "answer_pdf_sha1": "4ceedca82e31", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00053', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '在挪威（Norway）北部海岸外有一固定洋流與北大西洋暖流相連，俗稱挪威海流，該洋流性質與流向為 何？', '["冷流；流向為東北", "冷流；流向為西南", "暖流；流向為東北", "暖流；流向為西南"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d30ec6e36a01", "answer_pdf_sha1": "4ceedca82e31", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00054', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '執行航行船位校核時，下列敘述何者正確？', '["回音測深儀不具助航設備之價值", "多條目測方位所得之定位，通常為最不準確之船位", "在岸標不甚清晰時，浮標可以用來導航", "由電子航海所得之船位，最為準確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d30ec6e36a01", "answer_pdf_sha1": "4ceedca82e31", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00055', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '航海員欲透過三條位置線求取定位時，為使影響定位的誤差為最小，則兩個目標間之方位交角應選擇下列 何者為宜？', '["45°", "90°", "120°", "180°"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d30ec6e36a01", "answer_pdf_sha1": "4ceedca82e31", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00056', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '試問美國版海圖圖號為三位數字之比例尺(X)大小為何？', '["1：1,000,000≦(X)≦1：7,000,000", "1：2,000,000≦(X)≦1：9,000,000", "(X)≦1：2,000,000", "(X)≦1：5,000,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d30ec6e36a01", "answer_pdf_sha1": "4ceedca82e31", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
